// n8n Code node (Node.js)
// Builds a "VA Logistics + Schedule" email from the Airtable webhook payload
// Layout: single Placement Details table with 2 columns (label | value)
// OUTPUT includes: client_email + poc_email (and a deduped recipients_to you can map to Gmail)

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;
    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function formatDate(value) {
  if (!value) return "";
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

function normalizeEmail(email) {
  return String(email || "").trim();
}

function dedupeEmails(emails) {
  const out = [];
  const seen = new Set();
  for (const e of emails.map(normalizeEmail).filter(Boolean)) {
    const key = e.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(e);
  }
  return out;
}

return $input.all().map(item => {
  // Support both "body" payloads and plain json
  const root = item.json.body || item.json;
  const fields = root.fields || root;

  // --- Core fields ---
  const vaName =
    getField(fields, "Placed VA") ||
    getField(fields, "Virtual Assistant") ||
    getField(fields, "VA Name") ||
    getField(fields, "placedVA");

  const svEmail =
    getField(fields, "SV Email") ||
    getField(fields, "svEmail");

  const vaStartDate = formatDate(
    fields["VA Start Date"] || fields["vaStartDate"]
  );

  // --- Client + POC (for Gmail mapping) ---
  const clientName =
    getField(fields, "Client (text)") ||
    getField(fields, "Client") ||
    getField(fields, "Account Owner") ||
    getField(fields, "accountOwner");

  const accountOwnerEmail =
    getField(fields, "Account Owner Email") ||
    getField(fields, "Client Email") ||
    getField(fields, "clientEmail") ||
    getField(fields, "Email") ||
    getField(fields, "email");

  // POC fields (same logic you used elsewhere)
  const pocName = getField(fields, "POC Name (from PLACEMENTS Requirements)") || getField(fields, "POC Name");
  const pocPosition = getField(fields, "POC Position (from PLACEMENTS Requirements)") || getField(fields, "POC Position");
  const pocEmailRaw = getField(fields, "POC Email (from PLACEMENTS Requirements)") || getField(fields, "POC Email") || getField(fields, "pocEmail");
  const pocPhone = getField(fields, "POC Contact Number (from PLACEMENTS Requirements)") || getField(fields, "POC Contact Number") || getField(fields, "pocPhone");

  const hasAnyPoc = Boolean(pocName || pocEmailRaw || pocPhone || pocPosition);

  // Per your rule:
  // - If ANY POC value exists => treat POC as present, but fallback per-field to Account Owner email if missing
  // - If NO POC values exist => POC becomes Account Owner (same person), so we keep it consistent
  const client_email = normalizeEmail(accountOwnerEmail);
  const poc_email = normalizeEmail(hasAnyPoc ? (pocEmailRaw || accountOwnerEmail) : accountOwnerEmail);

  // For easy Gmail mapping (deduped)
  const recipients_to = dedupeEmails([client_email, poc_email]);

  // --- Logistics (supports text, arrays, Airtable linked records) ---
  let logisticsField =
    fields["Logistics For VA"] ||
    fields["Logistics for VA"] ||
    fields["vaLogistics"];

  let logisticsLines = [];

  if (Array.isArray(logisticsField)) {
    for (const entry of logisticsField) {
      if (entry == null) continue;
      if (typeof entry === "string" || typeof entry === "number") {
        logisticsLines.push(String(entry));
      } else if (typeof entry === "object") {
        if ("name" in entry) logisticsLines.push(String(entry.name));
        else logisticsLines.push(JSON.stringify(entry));
      }
    }
  } else if (typeof logisticsField === "string") {
    logisticsLines = logisticsField
      .split(/\r?\n/)
      .map(l => l.replace(/^[-•\u2022]\s*/, "").trim())
      .filter(Boolean);
  } else if (logisticsField != null) {
    logisticsLines.push(String(logisticsField));
  }

  const logisticsHtml = logisticsLines.length
    ? `<ul style="margin:4px 0 0 0;padding-left:20px;">${logisticsLines
        .map(line => `<li>${line}</li>`)
        .join("")}</ul>`
    : "TBD";

  // --- Schedule: use Day 1–Day 5 Schedule fields ---
  const dayFieldDefs = [
    { label: "Day 1", keys: ["Day 1 Schedule", "day1Schedule", "Day1Schedule", "day1"] },
    { label: "Day 2", keys: ["Day 2 Schedule", "day2Schedule", "Day2Schedule", "day2"] },
    { label: "Day 3", keys: ["Day 3 Schedule", "day3Schedule", "Day3Schedule", "day3"] },
    { label: "Day 4", keys: ["Day 4 Schedule", "day4Schedule", "Day4Schedule", "day4"] },
    { label: "Day 5", keys: ["Day 5 Schedule", "day5Schedule", "Day5Schedule", "day5"] },
  ];

  const scheduleRows = [];

  for (const def of dayFieldDefs) {
    let raw = "";
    for (const key of def.keys) {
      raw = getField(fields, key);
      if (raw) break;
    }
    if (!raw) continue;

    let dayLabel = def.label;
    let hours = raw;

    // If you store "MONDAY | 8 AM - 5 PM CST", respect that structure
    const parts = raw.split("|");
    if (parts.length > 1) {
      dayLabel = (parts[0] || def.label).trim();
      hours = (parts[1] || "").trim();
    }

    if (!dayLabel && !hours) continue;

    scheduleRows.push({ day: dayLabel, hours });
  }

  const scheduleHtml = scheduleRows.length
    ? `
      <table cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-top:4px;">
        ${scheduleRows
          .map(
            r => `
          <tr>
            <td style="padding:4px 8px;border:1px solid #e0e0e0;background-color:#fff7d9;white-space:nowrap;">${r.day}</td>
            <td style="padding:4px 12px;border:1px solid #e0e0e0;white-space:nowrap;">${r.hours}</td>
          </tr>`
          )
          .join("")}
      </table>`
    : "TBD";

  // --- Email subject ---
  const subject = `VA Logistics – ${vaName || "Virtual Assistant"}`;

  // --- Styles for main 2-column table ---
  const labelCell =
    "border:1px solid #e0e0e0;padding:10px 14px;width:30%;background-color:#f2f2f2;font-weight:bold;vertical-align:top;";
  const valueCell =
    "border:1px solid #e0e0e0;padding:10px 14px;vertical-align:top;";

  const html = `<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${subject}</title>
  </head>
  <body style="margin:0;padding:24px;font-family:Arial,Helvetica,sans-serif;font-size:14px;background-color:#f5f5f5;">
    <table align="center" width="650" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-collapse:collapse;margin:0 auto;">
      <tr>
        <td style="padding:24px;">
          <p style="margin:0 0 8px 0;">Hi,</p>
          <p style="margin:0 0 12px 0;">
            Thank you very much for your time and congratulations on hiring your Virtual Assistant in Scale Virtually!
          </p>
          <p style="margin:0 0 20px 0;">
            Before we get started on your VA, here are some follow-ups and logistics that we'll need from you:
          </p>

          <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-top:4px;">
            <tr>
              <td colspan="2"
                  style="background-color:#f7941d;
                         color:#ffffff;
                         font-weight:bold;
                         padding:10px 14px;
                         text-align:center;
                         font-size:14px;
                         text-transform:uppercase;">
                PLACEMENT DETAILS
              </td>
            </tr>

            <tr>
              <td style="${labelCell}">Logistics for VA</td>
              <td style="${valueCell}">${logisticsHtml}</td>
            </tr>

            <tr>
              <td style="${labelCell}">Schedule for VA</td>
              <td style="${valueCell}">${scheduleHtml}</td>
            </tr>

            <tr>
              <td style="${labelCell}">VA Name</td>
              <td style="${valueCell}">${vaName || "TBD"}</td>
            </tr>

            <tr>
              <td style="${labelCell}">SV Email</td>
              <td style="${valueCell}">
                ${
                  svEmail
                    ? `<a href="mailto:${svEmail}" style="color:#1976d2;">${svEmail}</a>`
                    : "TBD"
                }
              </td>
            </tr>

            <tr>
              <td style="${labelCell}">VA Start Date</td>
              <td style="${valueCell}">${vaStartDate || "TBD"}</td>
            </tr>
          </table>

          <p style="margin-top:20px;">
            You will also receive a docusign that you will need to complete before the VA start date with just a confirmation on the agreement that you have with Scale Virtually.

          </p>

          <p style="margin-top:8px;">
            Please don't hesitate if there are questions or clarifications. Looking forward to hearing from you soon!
          </p>
        </td>
      </tr>
    </table>
  </body>
</html>`;

  return {
    json: {
      subject,
      email_html: html,

      // ✅ for Gmail mapping
      client_name: clientName || "",
      client_email,      // account owner email
      poc_email,         // per your rule (POC if any exists, else account owner)
      recipients_to,     // deduped array of emails
      to: recipients_to.join(", "), // convenient string for Gmail "To"
    },
  };
});

// n8n Code node (Node.js)
// Builds a "Placement + Training VA Details + VA Work Details" email from the Airtable webhook payload

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;
    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function formatCurrency(value, symbol = "$") {
  if (value === undefined || value === null || value === "") return "";
  const num = Number(value);
  if (Number.isNaN(num)) return String(value);
  return (
    symbol +
    num.toLocaleString("en-US", {
      minimumFractionDigits: 0,
      maximumFractionDigits: 2,
    })
  );
}

function formatDate(value) {
  if (!value) return "";
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

return $input.all().map((item) => {
  const body = item.json.body || {};
  const fields = body.fields || {};

  // --- Placements Details ---
  const role = getField(fields, "Role (Rollup)");
  const numVAs = fields["Number of VA/s"] ?? "";
  const fullPartTime = getField(fields, "Full/Part Time");

  // Updated: Prioritize Final Client Rate over Client Rate
  const finalClientRateRaw = Array.isArray(fields["Final Client Rate"])
    ? fields["Final Client Rate"][0]
    : fields["Final Client Rate"];
  const regularClientRateRaw = Array.isArray(fields["Client Rate"])
    ? fields["Client Rate"][0]
    : fields["Client Rate"];

  const clientRateNum = (finalClientRateRaw != null && finalClientRateRaw !== "") 
    ? finalClientRateRaw 
    : regularClientRateRaw;

  const clientRate = formatCurrency(clientRateNum);
  const clientOTRate = formatCurrency(fields["Client OT Rate"]);
  const jdUrl = Array.isArray(fields["JD + Client Profile"])
    ? fields["JD + Client Profile"][0]
    : fields["JD + Client Profile"];
  const interviewer = getField(
    fields,
    "Requirement POC / POCs (Interviewers from Placements Requirements)"
  );

  // --- Account Details ---
  const clientTz = getField(fields, "Time Zone");
  const sufNum = Array.isArray(fields["SUF"]) ? fields["SUF"][0] : fields["SUF"];
  const suf = formatCurrency(sufNum);
  const companyName = getField(fields, "Company (text)");
  const companyAddress = getField(fields, "Company Address");
  const accountOwner = getField(fields, "Client (text)");
  const accountOwnerPhone = getField(fields, "Account Owner Contact Details");
  const accountOwnerEmail = getField(fields, "Account Owner Email");

  // --- Point of Contact (use POC fields only if ANY POC value exists; otherwise use Account Owner) ---
  const pocName = getField(fields, "POC Name (from PLACEMENTS Requirements)");
  const pocPosition = getField(fields, "POC Position (from PLACEMENTS Requirements)");
  const pocEmail = getField(fields, "POC Email (from PLACEMENTS Requirements)");
  const pocPhone = getField(fields, "POC Contact Number (from PLACEMENTS Requirements)");

  const hasAnyPoc = Boolean(pocName || pocEmail || pocPhone || pocPosition);

  // If we're in "POC mode", use POC values where present, but fall back per-field to Account Owner values
  const poClient = hasAnyPoc ? (pocName || accountOwner) : accountOwner;
  const poPhone  = hasAnyPoc ? (pocPhone || accountOwnerPhone) : accountOwnerPhone;
  const poEmail  = hasAnyPoc ? (pocEmail || accountOwnerEmail) : accountOwnerEmail;

  // Only show position if we're actually using the POC name (avoids "(position)" on fallback name)
  const poDisplayName =
    (poClient || "") + (hasAnyPoc && pocName && pocPosition ? ` (${pocPosition})` : "");

  // --- VA Work Details ---
  const vaName =
    getField(fields, "Virtual Assistant (from Placed VA)") ||
    getField(fields, "Placed VA");
  const vaRole = role;
  const vaStartDateISO = fields["VA Start Date"];
  const vaStartDate = formatDate(vaStartDateISO);

  const workScheduleText = getField(fields, "Work Schedule");
  const restDays = getField(fields, "Rest Days");
  const numHours = getField(fields, "Number of Working Hours");

  // Day X schedule fields
  const day1 = getField(fields, "Day 1 Schedule");
  const day2 = getField(fields, "Day 2 Schedule");
  const day3 = getField(fields, "Day 3 Schedule");
  const day4 = getField(fields, "Day 4 Schedule");
  const day5 = getField(fields, "Day 5 Schedule");

  let workSchedule = workScheduleText || "";

  // Add Rest Days and Working Hours
  if (restDays) {
    workSchedule += (workSchedule ? "<br/>" : "") + `Rest Days: ${restDays}`;
  }
  if (numHours) {
    workSchedule += (workSchedule ? "<br/>" : "") + `Working Hours: ${numHours}`;
  }

  // Append Day X Schedules into a single field
  const dayLines = [];
  if (day1) dayLines.push(`Day 1: ${day1}`);
  if (day2) dayLines.push(`Day 2: ${day2}`);
  if (day3) dayLines.push(`Day 3: ${day3}`);
  if (day4) dayLines.push(`Day 4: ${day4}`);
  if (day5) dayLines.push(`Day 5: ${day5}`);

  if (dayLines.length) {
    const dayBlock = dayLines.join("<br/>");
    workSchedule += (workSchedule ? "<br/><br/>" : "") + dayBlock;
  }

  if (!workSchedule) workSchedule = "TBD";

  // --- Additional Notes (Formatted as Bullets) ---
  const rawAdditionalNotes = getField(fields, "Additional Notes");
  let additionalNotesHtml = "";

  if (rawAdditionalNotes) {
    const notesLines = rawAdditionalNotes
      .split(/\r?\n/)
      .map((l) => l.replace(/^[-•\u2022]\s*/, "").trim())
      .filter(Boolean);

    if (notesLines.length) {
      additionalNotesHtml =
        '<ul style="margin:4px 0 0 0;padding-left:20px;">' +
        notesLines.map((line) => `<li>${line}</li>`).join("") +
        "</ul>";
    }
  }

  // --- VA Details [Training] (Personal Email, Phone, SV Rate, SV Email) ---
  const personalEmail = getField(fields, "Personal Email");
  const phoneNumber = getField(fields, "Phone Number");

  // Updated: Prioritize Final SV Base Rate over SV Base Rate
  const finalSvBaseRateStr = getField(fields, "Final SV Base Rate");
  const svBaseRateStr = getField(fields, "SV Base Rate");
  const activeSvBaseRate = finalSvBaseRateStr || svBaseRateStr;

  const vaRate = activeSvBaseRate ? formatCurrency(activeSvBaseRate) + "/hr" : "";
  const svEmail = getField(fields, "SV Email");

  // --- Login Credentials (from Logistics Needed field) ---
  const logisticsField = fields["Logistics For VA"];
  let loginLines = [];

  if (Array.isArray(logisticsField)) {
    for (const entry of logisticsField) {
      if (entry == null) continue;
      if (typeof entry === "string" || typeof entry === "number") {
        loginLines.push(String(entry));
      } else if (typeof entry === "object") {
        if ("name" in entry) loginLines.push(String(entry.name));
        else loginLines.push(JSON.stringify(entry));
      }
    }
  } else if (typeof logisticsField === "string") {
    loginLines = logisticsField
      .split(/\r?\n/)
      .map((l) => l.replace(/^[-•\u2022]\s*/, "").trim())
      .filter(Boolean);
  } else if (logisticsField != null) {
    loginLines.push(String(logisticsField));
  }

  let loginCredentialsHtml;
  if (loginLines.length) {
    loginCredentialsHtml =
      '<ul style="margin:4px 0 0 0;padding-left:20px;">' +
      loginLines.map((line) => `<li>${line}</li>`).join("") +
      "</ul>";
  } else {
    loginCredentialsHtml = "TBD";
  }

  // --- Email subject ---
  const subject = `New VA Placement – ${vaName || "Virtual Assistant"} for ${
    companyName || accountOwner || "Client"
  }`;

  // Styles
  const labelCellGray =
    "border:1px solid #e0e0e0;padding:8px 12px;width:40%;background-color:#f2f2f2;";
  const labelCellYellow =
    "border:1px solid #e0e0e0;padding:8px 12px;width:40%;background-color:#fff7d9;";

  // --- VA DETAILS [TRAINING] HTML (Now displays unconditionally) ---
  const trainingSectionHtml = `
    <tr>
      <td style="padding:16px 24px 0 24px;">
        <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;">
          <tr>
            <td colspan="2" style="background-color:#333333;color:#ffffff;font-weight:bold;padding:8px 12px;text-align:center;">
              VA DETAILS [TRAINING]
            </td>
          </tr>
          <tr>
            <td style="${labelCellGray}"><strong>VA Name</strong></td>
            <td style="border:1px solid #e0e0e0;padding:8px 12px;">${vaName || ""}</td>
          </tr>
          <tr>
            <td style="${labelCellGray}"><strong>Personal Email</strong></td>
            <td style="border:1px solid #e0e0e0;padding:8px 12px;">
              ${
                personalEmail
                  ? `<a href="mailto:${personalEmail}" style="color:#1976d2;">${personalEmail}</a>`
                  : ""
              }
            </td>
          </tr>
          <tr>
            <td style="${labelCellGray}"><strong>Phone Number</strong></td>
            <td style="border:1px solid #e0e0e0;padding:8px 12px;">${phoneNumber || ""}</td>
          </tr>
          <tr>
            <td style="${labelCellGray}"><strong>VA Rate</strong></td>
            <td style="border:1px solid #e0e0e0;padding:8px 12px;">${vaRate || ""}</td>
          </tr>
          <tr>
            <td style="${labelCellGray}"><strong>SV Email</strong></td>
            <td style="border:1px solid #e0e0e0;padding:8px 12px;">
              ${
                svEmail
                  ? `<a href="mailto:${svEmail}" style="color:#1976d2;">${svEmail}</a>`
                  : ""
              }
            </td>
          </tr>
        </table>
      </td>
    </tr>`;

  const html = `<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${subject}</title>
  </head>
  <body style="margin:0;padding:24px 0;background-color:#f5f5f5;font-family:Arial,Helvetica,sans-serif;">
    <table align="center" width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-collapse:collapse;margin:0 auto;">
      <tr>
        <td style="padding:24px 24px 12px 24px;font-size:16px;">
          <p style="margin:0 0 8px 0;">Hi Ops Team,</p>
          <p style="margin:0 0 16px 0;">Please see new endorsement below:</p>
          <p style="margin:0;">
            <strong>Client:</strong> ${companyName || accountOwner || ""}<br/>
            <strong>VA:</strong> ${vaName || ""}<br/>
            <strong>Role:</strong> ${role || ""}<br/>
            <strong>Start Date:</strong> ${vaStartDate || ""}
          </p>
        </td>
      </tr>

      <tr>
        <td style="padding:0 24px 0 24px;">
          <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;">
            <tr>
              <td colspan="2" style="background-color:#333333;color:#ffffff;font-weight:bold;padding:8px 12px;text-align:center;">
                PLACEMENTS DETAILS
              </td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Role/s</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${role || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Number of VAs</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${numVAs || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Part Time / Full Time</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${fullPartTime || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Client Rate</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${
                clientRate || ""
              }${clientOTRate ? ` (OT: ${clientOTRate})` : ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>JD + Client Profile</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">
                ${
                  jdUrl
                    ? `<a href="${jdUrl}" target="_blank" style="color:#1976d2;">View JD Link</a>`
                    : ""
                }
              </td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Interviewer</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${interviewer || ""}</td>
            </tr>
          </table>
        </td>
      </tr>

      <tr>
        <td style="padding:16px 24px 0 24px;">
          <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;font-size:13px;">
            <tr>
              <td colspan="2" style="background-color:#333333;color:#ffffff;font-weight:bold;padding:8px 12px;text-align:center;">
                ACCOUNT DETAILS
              </td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Client Timezone</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${clientTz || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>SUF</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${suf || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Company Name</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${companyName || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Company Address</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${companyAddress || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Account Owner (aka client / CSA Signatory)</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">${accountOwner || ""}</td>
            </tr>
            <tr>
              <td style="${labelCellGray}"><strong>Account Owner Contact Details</strong></td>
              <td style="border:1px solid #e0e0e0;padding:8px 12px;">
                ${accountOwnerPhone ? `Mobile: ${accountOwnerPhone}<br/>` : ""}
                ${
                  accountOwnerEmail
