// n8n Code node (Node.js)
// Builds a "VA Logistics + Schedule" email from the Airtable webhook payload
// Layout: single Placement Details table with 2 columns (label | value)
// OUTPUT includes: client_email + poc_email (and a deduped recipients_to you can map to Gmail)

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;
    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function formatDate(value) {
  if (!value) return "";
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

function normalizeEmail(email) {
  return String(email || "").trim();
}

function dedupeEmails(emails) {
  const out = [];
  const seen = new Set();
  for (const e of emails.map(normalizeEmail).filter(Boolean)) {
    const key = e.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(e);
  }
  return out;
}

return $input.all().map(item => {
  // Support both "body" payloads and plain json
  const root = item.json.body || item.json;
  const fields = root.fields || root;

  // --- Core fields ---
  const vaName =
    getField(fields, "Placed VA") ||
    getField(fields, "Virtual Assistant") ||
    getField(fields, "VA Name") ||
    getField(fields, "placedVA");

  const svEmail =
    getField(fields, "SV Email") ||
    getField(fields, "svEmail");

  const vaStartDate = formatDate(
    fields["VA Start Date"] || fields["vaStartDate"]
  );

  // --- Client + POC (for Gmail mapping) ---
  const clientName =
    getField(fields, "Client (text)") ||
    getField(fields, "Client") ||
    getField(fields, "Account Owner") ||
    getField(fields, "accountOwner");

  const accountOwnerEmail =
    getField(fields, "Account Owner Email") ||
    getField(fields, "Client Email") ||
    getField(fields, "clientEmail") ||
    getField(fields, "Email") ||
    getField(fields, "email");

  // POC fields (same logic you used elsewhere)
