  const pocPhone = getField(fields, "POC Contact Number (from PLACEMENTS Requirements)") || getField(fields, "POC Contact Number") || getField(fields, "pocPhone");

  const hasAnyPoc = Boolean(pocName || pocEmailRaw || pocPhone || pocPosition);

  // Per your rule:
  // - If ANY POC value exists => treat POC as present, but fallback per-field to Account Owner email if missing
  // - If NO POC values exist => POC becomes Account Owner (same person), so we keep it consistent
  const client_email = normalizeEmail(accountOwnerEmail);
  const poc_email = normalizeEmail(hasAnyPoc ? (pocEmailRaw || accountOwnerEmail) : accountOwnerEmail);

  // For easy Gmail mapping (deduped)
  const recipients_to = dedupeEmails([client_email, poc_email]);

  // --- Logistics (supports text, arrays, Airtable linked records) ---
  let logisticsField =
    fields["Logistics For VA"] ||
