        .map(line => `<li>${line}</li>`)
        .join("")}</ul>`
    : "TBD";

  // --- Schedule: use Day 1–Day 5 Schedule fields ---
  const dayFieldDefs = [
    { label: "Day 1", keys: ["Day 1 Schedule", "day1Schedule", "Day1Schedule", "day1"] },
    { label: "Day 2", keys: ["Day 2 Schedule", "day2Schedule", "Day2Schedule", "day2"] },
