      <tr>
        <td style="padding:24px;">
          <p style="margin:0 0 8px 0;">Hi,</p>
          <p style="margin:0 0 12px 0;">
            Thank you very much for your time and congratulations on hiring your Virtual Assistant in Scale Virtually!
          </p>
          <p style="margin:0 0 20px 0;">
