      // ✅ for Gmail mapping
      client_name: clientName || "",
      client_email,      // account owner email
      poc_email,         // per your rule (POC if any exists, else account owner)
      recipients_to,     // deduped array of emails
      to: recipients_to.join(", "), // convenient string for Gmail "To"
    },
  };
});

// n8n Code node (Node.js)
// Builds a "Placement + Training VA Details + VA Work Details" email from the Airtable webhook payload

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;
    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function formatCurrency(value, symbol = "$") {
  if (value === undefined || value === null || value === "") return "";
  const num = Number(value);
  if (Number.isNaN(num)) return String(value);
  return (
    symbol +
    num.toLocaleString("en-US", {
      minimumFractionDigits: 0,
      maximumFractionDigits: 2,
    })
  );
}

function formatDate(value) {
  if (!value) return "";
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

return $input.all().map((item) => {
  const body = item.json.body || {};
  const fields = body.fields || {};

  // --- Placements Details ---
  const role = getField(fields, "Role (Rollup)");
  const numVAs = fields["Number of VA/s"] ?? "";
  const fullPartTime = getField(fields, "Full/Part Time");

  // Updated: Prioritize Final Client Rate over Client Rate
  const finalClientRateRaw = Array.isArray(fields["Final Client Rate"])
    ? fields["Final Client Rate"][0]
    : fields["Final Client Rate"];
  const regularClientRateRaw = Array.isArray(fields["Client Rate"])
    ? fields["Client Rate"][0]
    : fields["Client Rate"];

  const clientRateNum = (finalClientRateRaw != null && finalClientRateRaw !== "") 
    ? finalClientRateRaw 
    : regularClientRateRaw;

  const clientRate = formatCurrency(clientRateNum);
  const clientOTRate = formatCurrency(fields["Client OT Rate"]);
  const jdUrl = Array.isArray(fields["JD + Client Profile"])
    ? fields["JD + Client Profile"][0]
    : fields["JD + Client Profile"];
  const interviewer = getField(
    fields,
    "Requirement POC / POCs (Interviewers from Placements Requirements)"
  );

  // --- Account Details ---
  const clientTz = getField(fields, "Time Zone");
  const sufNum = Array.isArray(fields["SUF"]) ? fields["SUF"][0] : fields["SUF"];
  const suf = formatCurrency(sufNum);
  const companyName = getField(fields, "Company (text)");
  const companyAddress = getField(fields, "Company Address");
  const accountOwner = getField(fields, "Client (text)");
  const accountOwnerPhone = getField(fields, "Account Owner Contact Details");
  const accountOwnerEmail = getField(fields, "Account Owner Email");

  // --- Point of Contact (use POC fields only if ANY POC value exists; otherwise use Account Owner) ---
  const pocName = getField(fields, "POC Name (from PLACEMENTS Requirements)");
  const pocPosition = getField(fields, "POC Position (from PLACEMENTS Requirements)");
  const pocEmail = getField(fields, "POC Email (from PLACEMENTS Requirements)");
  const pocPhone = getField(fields, "POC Contact Number (from PLACEMENTS Requirements)");

  const hasAnyPoc = Boolean(pocName || pocEmail || pocPhone || pocPosition);

  // If we're in "POC mode", use POC values where present, but fall back per-field to Account Owner values
  const poClient = hasAnyPoc ? (pocName || accountOwner) : accountOwner;
  const poPhone  = hasAnyPoc ? (pocPhone || accountOwnerPhone) : accountOwnerPhone;
  const poEmail  = hasAnyPoc ? (pocEmail || accountOwnerEmail) : accountOwnerEmail;

  // Only show position if we're actually using the POC name (avoids "(position)" on fallback name)
  const poDisplayName =
    (poClient || "") + (hasAnyPoc && pocName && pocPosition ? ` (${pocPosition})` : "");

  // --- VA Work Details ---
  const vaName =
    getField(fields, "Virtual Assistant (from Placed VA)") ||
    getField(fields, "Placed VA");
  const vaRole = role;
  const vaStartDateISO = fields["VA Start Date"];
  const vaStartDate = formatDate(vaStartDateISO);

  const workScheduleText = getField(fields, "Work Schedule");
  const restDays = getField(fields, "Rest Days");
  const numHours = getField(fields, "Number of Working Hours");

  // Day X schedule fields
  const day1 = getField(fields, "Day 1 Schedule");
  const day2 = getField(fields, "Day 2 Schedule");
  const day3 = getField(fields, "Day 3 Schedule");
  const day4 = getField(fields, "Day 4 Schedule");
  const day5 = getField(fields, "Day 5 Schedule");

  let workSchedule = workScheduleText || "";

  // Add Rest Days and Working Hours
  if (restDays) {
    workSchedule += (workSchedule ? "<br/>" : "") + `Rest Days: ${restDays}`;
  }
  if (numHours) {
    workSchedule += (workSchedule ? "<br/>" : "") + `Working Hours: ${numHours}`;
  }

  // Append Day X Schedules into a single field
  const dayLines = [];
  if (day1) dayLines.push(`Day 1: ${day1}`);
  if (day2) dayLines.push(`Day 2: ${day2}`);
