parameters.jsCode:
// n8n Code node (Node.js)
// "Congratulations" email styled like the Logistics email
// - Orange banner at the top
// - Centered hero image from "VA Image" (350px wide)
// - Gray banner BELOW the hero image with:
//    1) VA Name (white)  ✅ moved here
//    2) Client name (orange)
//    3) Role (white)
// - Body text pulled from "VA Email Body" (if present) else uses default messaging
// - Bold the "Additionally..." PAD note
// - Closing: "Best Regards, Scale Virtually Placements Team"

function getField(fields, key, fb = "") {
  const raw = fields[key];
  if (raw === undefined || raw === null) return fb;

  if (Array.isArray(raw)) {
    if (raw.length === 0) return fb;

    const first = raw[0];
    if (first === null || first === undefined) return fb;

    if (typeof first === "object") {
      if ("name" in first) return String(first.name);
      return JSON.stringify(first);
    }
    return String(first);
  }

  if (typeof raw === "object") {
    if ("name" in raw) return String(raw.name);
    return JSON.stringify(raw);
  }

  return String(raw);
}

function getAttachmentUrl(fields, key) {
  const raw = fields[key];
  if (!raw || !Array.isArray(raw) || raw.length === 0) return "";
  const first = raw[0];
  if (first && typeof first === "object" && first.url) return String(first.url);
  return "";
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function textToParagraphs(text) {
  if (!text) return "";
  const blocks = String(text).split(/\r?\n\r?\n/);

  return blocks
    .map((block) => {
      const trimmed = String(block).trim();
      const isBold = /^Additionally,/.test(trimmed);

      const safe = escapeHtml(block).replace(/\r?\n/g, "<br>");
      const content = isBold ? `<strong>${safe}</strong>` : safe;

      return `<p style="margin:0 0 12px 0;">${content}</p>`;
    })
    .join("");
}

function buildEmail(item) {
  const root = item.json.body || item.json;
  const fields = root.fields || root;

  // ✅ Prefer this lookup for VA Name
  const vaName =
    getField(fields, "Virtual Assistant (from Placed VA)") ||
    getField(fields, "Virtual Assistant") ||
    getField(fields, "Placed VA") ||
    getField(fields, "VA Name") ||
    getField(fields, "placedVA") ||
    "";

  const clientName = getField(fields, "Client (text)") || "";
  const roleName = getField(fields, "Role (Rollup)") || "";

  const defaultBodyText = `Kindly expect an email and a calendar invite from the Operations Team, which will provide details about your upcoming handoff date for your client. Our primary goal is to ensure a seamless transition for you and equip you with all the necessary resources to perform your tasks with the utmost effectiveness.

We truly value the valuable skills and experience you bring to our team, and we have every confidence that you will be a valuable asset to the client's organization. We are excited to witness your success and growth in your new role.

If you have any questions or concerns in the meantime, please don't hesitate to reach out to us. Our team is fully available to support you with anything you require to kickstart your journey.

Additionally, before proceeding to Operations, we kindly request you to sign the DocuSign Placements Acknowledgement Documents (PAD), which will be on a separate email. Signing these documents is crucial for the continuation of the onboarding process. Should you fail to sign the PAD, we will be unable to move forward with the onboarding process.

Thank you, and we are looking forward to working together.`;

  const emailBodyText =
    getField(fields, "VA Email Body") ||
    getField(fields, "Email Body") ||
    getField(fields, "emailBody") ||
    getField(fields, "Body") ||
    defaultBodyText;

  const bodyHtml = textToParagraphs(emailBodyText);

  const closingHtml = `
    <p style="margin:16px 0 4px 0;">Best Regards,</p>
    <p style="margin:0 0 0 0;"><strong>Scale Virtually Placements Team</strong></p>
  `;

  const heroUrl = getAttachmentUrl(fields, "VA Image");
  const heroHtml = heroUrl
    ? `
      <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin:0 0 12px 0;">
        <tr>
          <td align="center" style="padding:0;">
            <img src="${heroUrl}"
                 alt="${escapeHtml(vaName || "Virtual Assistant")}"
                 width="350"
                 style="display:block;max-width:350px;width:350px;height:auto;border:0;" />
          </td>
        </tr>
      </table>`
    : "";

  const headerHtml = `
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin:0 0 18px 0;">
      <tr>
        <td style="
          background-color:#f7941d;
          color:#ffffff;
          font-weight:bold;
          padding:14px 14px;
          text-align:center;
          font-size:18px;
          text-transform:uppercase;
        ">
          CONGRATULATIONS ON GETTING SELECTED!
        </td>
      </tr>
    </table>`;

  // ✅ VA Name placed ABOVE Client + Role inside the same gray banner
  const clientRoleBannerHtml =
    vaName || clientName || roleName
      ? `
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;margin:0 0 18px 0;">
      <tr>
        <td style="background-color:#3f3f3f;padding:12px 14px;text-align:center;">
          ${
            vaName
              ? `<div style="color:#ffffff;font-weight:800;font-size:18px;line-height:1.2;margin-bottom:6px;">
                  ${escapeHtml(vaName)}
                </div>`
              : ``
          }
          ${
            clientName
              ? `<div style="color:#f7941d;font-weight:800;font-size:16px;letter-spacing:.8px;text-transform:uppercase;line-height:1.2;">
                  ${escapeHtml(clientName)}
                </div>`
              : ``
          }
          ${
            roleName
              ? `<div style="color:#ffffff;font-weight:700;font-size:12px;letter-spacing:1px;text-transform:uppercase;line-height:1.2;margin-top:4px;">
                  ${escapeHtml(roleName)}
                </div>`
              : ``
          }
        </td>
      </tr>
    </table>`
      : "";

  const subjectName = vaName || "You";
  const subject = `Congratulations ${subjectName}! You've been selected!`;

  const html = `<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8" />
    <title>${escapeHtml(subject)}</title>
  </head>
  <body style="margin:0;padding:24px;font-family:Arial,Helvetica,sans-serif;font-size:14px;background-color:#f5f5f5;">
    <table align="center" width="650" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-collapse:collapse;margin:0 auto;">
      <tr>
        <td style="padding:24px;">
          ${headerHtml}
          ${heroHtml}
          ${clientRoleBannerHtml}
          ${bodyHtml}
          ${closingHtml}
        </td>
      </tr>
    </table>
  </body>
</html>`;

  return {
    json: {
      subject,
      email_html: html,
      vaName: vaName || null,
      heroUrl: heroUrl || null,
      clientName: clientName || null,
      roleName: roleName || null,
    },
  };
}

return $input.all().map(buildEmail);

