// n8n Code node (Node.js)
// PURPOSE:
// - Start with a hardcoded list of Client Services Slack User IDs
// - Add the Slack User ID returned by your Slack API lookupByEmail HTTP Request
// - Also add the optional "SC Slack User ID" coming from your webhook/Airtable payload
// - Output: { targetSlackIds: [...] }
//
// EXPECTED WORKFLOW WIRING (recommended):
// Trigger/Webhook -> HTTP Request (Slack users.lookupByEmail) -> THIS Code node
// In the HTTP Request, set email from your webhook data via expression.
//
// IMPORTANT:
// - This Code node will receive the HTTP Request response in items[0].json
// - We read the webhook payload via $node["<YOUR WEBHOOK NODE NAME>"]

// 1) Hardcoded list of Client Services Team IDs
const clientServicesIds = [
  "U05M03YMMG9", // Ace Caracuel
  "U05J6CWMM2A", // Aja Mojica
  "U09FT84PWHE", // Alexandrea Layson
  "U07Q1JXLNHM", // Christine Kate Cabuntas
  "U079HKXJUF4", // Fiona Cafe
  "U091Q0QFNKE", // Gellyn Ponteras
  "U08PB377Y94", // Jan Karlo Alcantara
  "U03TR5B81QU", // Janssen Miraflor
  "U09MLQJC3K5", // Jenneiline Marie Manuel
  "U03MFHTSS79", // Jesy Jopio
  "U06FX7RANDA", // Jianna Louise Caritativo
  // "U03MYJ52F9S", // Kenneth Roy Pan
  "U09654L4H0A", // Patrick Jansen Villanueva
  // "U0ACU6YF12L", //Bam Alota
  "U070Q7H8NKA", //April Diane Vitug
  "U0932J0TPED", //Cherry Versola
  "U03N2NPTLJ0", //Jamaica David
  "U08KWMTUZ28", //Jan Marie Felix
  "U06FSPKURQB", //Jimbert Paul Celajes
  "U05KAKXLX1Q", //Marijoy Orbegoso
  "U03TQJSAD1S", //Priam Abayon
  "U04P08JUNSV", //Rhea Angelique Trias
  "U06A96JFGRK", //Robert Anthony Estrada
  "U0B1RNVFPJA", //Ella Etorma
  "U0B1RNWU5HU", //Marc Arboleda
];

// 2) Get Slack user ID from the HTTP Request response (users.lookupByEmail)
//    Response shape: { ok: true, user: { id: "U123...", ... } }
const slackLookup = items[0]?.json ?? {};
const lookedUpUserId = slackLookup?.user?.id || "";

// 3) Get the optional "SC Slack User ID" from the webhook payload
//    Change this node name to your actual webhook/trigger node name in n8n.
const WEBHOOK_NODE_NAME = "Webhook"; // <-- rename to your real node name

const webhookJson = $node[WEBHOOK_NODE_NAME]?.json ?? {};
const webhookFields = webhookJson?.body?.fields ?? {};

// Airtable may send this as string OR array OR undefined
const scSlackId = webhookFields["SC Slack User ID"];

// 4) Build final unique list
let finalUserIds = [...clientServicesIds];

function addId(id) {
  if (!id) return;

  if (Array.isArray(id)) {
    id.forEach(addId);
    return;
  }

  if (typeof id === "string" && id.trim() && !finalUserIds.includes(id.trim())) {
    finalUserIds.push(id.trim());
  }
}

// Add the looked-up user ID (from email)
addId(lookedUpUserId);

// Add the SC Slack User ID (from webhook)
addId(scSlackId);

// 5) Return output
return [
  {
    json: {
      targetSlackIds: finalUserIds,
      slackLookupOk: slackLookup?.ok ?? null,
      slackLookupError: slackLookup?.error ?? null,
    },
  },
];

/*
USAGE NOTES:

A) In your Slack "Invite a user to a channel" node:
   - If it expects a comma-separated string:
       users = {{ $json.targetSlackIds.join(',') }}
   - If it accepts an array directly:
       users = {{ $json.targetSlackIds }}

B) If your HTTP Request node is NOT immediately before this Code node,
   you can also read it by node name:
       const lookedUpUserId = $node["Get Slack User ID"].json?.user?.id;
   (Only do this if that node is guaranteed to execute before this node.)
*/
